   143→                            height: max(
   144→                                0,
   145→                                geometry.size.height * CGFloat(clampedLevel)
   146→                            )
   147→                        )
   148→                }
   149→            }
   150→            .frame(width: 24)
   151→
   152→            Text(label)
   153→                .font(.caption2)
   154→                .foregroundStyle(.secondary)
   155→        }
   156→    }
