    15→
    16→    var body: some View {
    17→        VStack(spacing: 16) {
    18→            Text(formattedDuration)
    19→                .font(.system(size: 48, weight: .light, design: .monospaced))
    20→                .foregroundStyle(state == .recording ? .primary : .secondary)
    21→
    22→            Text(stateLabel)
    23→                .font(.pabloBody(11))
    24→                .foregroundStyle(.secondary)
    25→                .textCase(.uppercase)
    26→
    27→            HStack(spacing: 24) {
    28→                LevelMeter(label: "Mic", level: micLevel)
