    40→
    41→    @ViewBuilder
    42→    private var systemAudioStatus: some View {
    43→        if state == .recording || state == .paused {
    44→            HStack(spacing: 6) {
    45→                Circle()
    46→                    .fill(systemAudioActive ? Color.pabloSage : Color.pabloBlush)
    47→                    .frame(width: 8, height: 8)
    48→                Text(systemAudioActive ? "System Audio: Active" : "System Audio: Unavailable")
    49→                    .font(.caption)
    50→                    .foregroundStyle(.secondary)
    51→            }
    52→        }
    53→    }
    54→
    55→    private var controlButtons: some View {
    56→        HStack(spacing: 20) {
    57→            switch state {
    58→            case .idle:
    59→                idleButtons
    60→            case .recording:
    61→                recordingButtons
    62→            case .paused:
    63→                pausedButtons
    64→            }
    65→        }
