   114→    private var formattedDuration: String {
   115→        let minutes = Int(duration) / 60
   116→        let seconds = Int(duration) % 60
   117→        return String(format: "%02d:%02d", minutes, seconds)
   118→    }
   119→
   120→    private var stateLabel: String {
   121→        switch state {
