   146→    }
   147→
   148→    /// Derives two-letter initials from the display name.
   149→    private var initials: String {
   150→        let words = displayName.split(separator: " ").map(String.init)
   151→        if words.count >= 2 {
   152→            if let first = words.first?.first, let last = words.last?.first {
   153→                return "\(first)\(last)".uppercased()
   154→            }
   155→        }
   156→        if let word = words.first {
   157→            let chars = word.prefix(2)
   158→            return chars.uppercased()
   159→        }
   160→        return "?"
   161→    }
