   178→// MARK: - Pure formatting helpers
   179→
   180→/// Converts "lastname, firstname" to "Firstname Lastname". Falls back to `.capitalized`.
   181→private func formatPatientName(_ raw: String) -> String {
   182→    guard raw.contains(", ") else {
   183→        return raw.capitalized
   184→    }
   185→    let parts = raw.components(separatedBy: ", ")
   186→    guard parts.count >= 2 else {
   187→        return raw.capitalized
   188→    }
   189→    // parts[0] = last name, parts[1] = first name
   190→    let reordered = [parts[1], parts[0]]
   191→    return reordered
   192→        .map(\.capitalized)
   193→        .joined(separator: " ")
   194→}
   195→
   196→/// Parses an ISO 8601 date string and formats it as "MMM d, yyyy".
   197→private func formatISODate(_ raw: String?) -> String? {
   198→    guard let raw else { return nil }
   199→    let iso = ISO8601DateFormatter()
   200→    if let date = iso.date(from: raw) {
   201→        let df = DateFormatter()
   202→        df.dateFormat = "MMM d, yyyy"
   203→        return df.string(from: date)
   204→    }
   205→    // ISO8601DateFormatter requires a time zone designator; try without
   206→    let isoNoTZ = ISO8601DateFormatter()
   207→    isoNoTZ.formatOptions = [
   208→        .withInternetDateTime,
   209→        .withDashSeparatorInDate,
   210→        .withColonSeparatorInTime,
   211→        .withFullDate,
   212→    ]
   213→    if let date = isoNoTZ.date(from: raw) {
   214→        let df = DateFormatter()
   215→        df.dateFormat = "MMM d, yyyy"
   216→        return df.string(from: date)
   217→    }
   218→    return raw
   219→}
