    81→struct PatientRow: View {
    82→    let patient: Patient
    83→
    84→    var body: some View {
    85→        HStack(spacing: 12) {
    86→            initialsAvatar
    87→            VStack(alignment: .leading, spacing: 4) {
    88→                Text(displayName)
    89→                    .font(.pabloDisplay(15))
