   111→            Text(patient.status.capitalized)
   112→                .font(.pabloBody(12))
   113→                .padding(.horizontal, 8)
   114→                .padding(.vertical, 3)
   115→                .background(statusColor.opacity(0.15))
   116→                .foregroundStyle(statusColor)
   117→                .clipShape(Capsule())
   118→        }
   119→        .padding(.horizontal, 16)
   120→        .padding(.vertical, 12)
   121→        .background(
   122→            RoundedRectangle(cornerRadius: 8)
   123→                .fill(Color.white)
   124→                .shadow(color: Color.black.opacity(0.06), radius: 4, x: 0, y: 2)
   125→        )
   126→    }
   127→
   128→    // MARK: - Subviews
   129→
   130→    private var initialsAvatar: some View {
   131→        ZStack {
   132→            Circle()
   133→                .fill(Color.pabloHoney.opacity(0.18))
   134→                .frame(width: 36, height: 36)
   135→            Text(initials)
   136→                .font(.system(size: 14, weight: .semibold))
   137→                .foregroundStyle(Color.pabloBrownDeep)
   138→        }
   139→    }
   140→
   141→    // MARK: - Helpers
   142→
   143→    /// Reformats "lastname, firstname" to "Firstname Lastname".
   144→    private var displayName: String {
   145→        formatPatientName(patient.fullName)
   146→    }
   147→
   148→    /// Derives two-letter initials from the display name.
   149→    private var initials: String {
   150→        let words = displayName.split(separator: " ").map(String.init)
   151→        if words.count >= 2 {
   152→            if let first = words.first?.first, let last = words.last?.first {
   153→                return "\(first)\(last)".uppercased()
   154→            }
   155→        }
   156→        if let word = words.first {
   157→            let chars = word.prefix(2)
   158→            return chars.uppercased()
   159→        }
   160→        return "?"
   161→    }
   162→
   163→    /// Formats the ISO last-session date string to "MMM d, yyyy", or nil if absent.
   164→    private var formattedLastSession: String? {
   165→        formatISODate(patient.lastSessionDate)
   166→    }
   167→
   168→    private var statusColor: Color {
   169→        switch patient.status.lowercased() {
   170→        case "active": .pabloSage
   171→        case "inactive": .gray
   172→        case "discharged": .pabloBlush
   173→        default: .secondary
   174→        }
   175→    }
   176→}
   177→
   178→// MARK: - Pure formatting helpers
   179→
   180→/// Converts "lastname, firstname" to "Firstname Lastname". Falls back to `.capitalized`.
   181→private func formatPatientName(_ raw: String) -> String {
   182→    guard raw.contains(", ") else {
   183→        return raw.capitalized
   184→    }
   185→    let parts = raw.components(separatedBy: ", ")
   186→    guard parts.count >= 2 else {
   187→        return raw.capitalized
   188→    }
   189→    // parts[0] = last name, parts[1] = first name
   190→    let reordered = [parts[1], parts[0]]
   191→    return reordered
   192→        .map(\.capitalized)
   193→        .joined(separator: " ")
   194→}
   195→
   196→/// Parses an ISO 8601 date string and formats it as "MMM d, yyyy".
   197→private func formatISODate(_ raw: String?) -> String? {
   198→    guard let raw else { return nil }
   199→    let iso = ISO8601DateFormatter()
   200→    if let date = iso.date(from: raw) {
   201→        let df = DateFormatter()
   202→        df.dateFormat = "MMM d, yyyy"
   203→        return df.string(from: date)
   204→    }
   205→    // ISO8601DateFormatter requires a time zone designator; try without
   206→    let isoNoTZ = ISO8601DateFormatter()
   207→    isoNoTZ.formatOptions = [
   208→        .withInternetDateTime,
   209→        .withDashSeparatorInDate,
   210→        .withColonSeparatorInTime,
   211→        .withFullDate,
   212→    ]
   213→    if let date = isoNoTZ.date(from: raw) {
   214→        let df = DateFormatter()
   215→        df.dateFormat = "MMM d, yyyy"
   216→        return df.string(from: date)
   217→    }
   218→    return raw
   219→}
